// src/pages/Inventario.jsx
import React, { useState } from 'react';
import NotaVenta from '../components/NotaVenta';
import './Inventario.css';

export default function Inventario({ productos, actualizarProducto, agregarProducto, clientes, ventas, agregarVenta }) {
  const [editando, setEditando]   = useState(null);
  const [formNew, setFormNew]     = useState({ nombre: '', unidad: 'kg', precio: '', stock: '' });
  const [mostrarForm, setMostrarForm] = useState(false);
  const [quickSale, setQuickSale] = useState({
    fecha: new Date().toISOString().split('T')[0],
    descripcion: '',
    tipo: 'kg',
    precioUnit: '',
    cantidad: '',
    clienteId: '',
    clienteNombre: '',
  });
  const [notaVisible, setNotaVisible] = useState(null);

  const handleSaveEdit = (prod) => {
    actualizarProducto(prod);
    setEditando(null);
  };

  const handleAgregar = () => {
    if (!formNew.nombre || !formNew.precio) return;
    agregarProducto({
      nombre: formNew.nombre,
      unidad: formNew.unidad,
      precio: parseFloat(formNew.precio),
      stock: parseFloat(formNew.stock) || 0,
    });
    setFormNew({ nombre: '', unidad: 'kg', precio: '', stock: '' });
    setMostrarForm(false);
  };

  const handleClienteChangeQuick = (id) => {
    const cli = clientes.find(c => c.id === Number(id));
    setQuickSale(f => ({ ...f, clienteId: id, clienteNombre: cli?.nombre || '' }));
  };

  const handleRegistrarVentaRapida = () => {
    if (!quickSale.descripcion.trim()) {
      alert('Escribe la descripción del producto.');
      return;
    }
    if (!quickSale.precioUnit || parseFloat(quickSale.precioUnit) <= 0) {
      alert('Ingresa un precio válido.');
      return;
    }
    if (!quickSale.cantidad || parseFloat(quickSale.cantidad) <= 0) {
      alert('Ingresa una cantidad válida.');
      return;
    }

    const cliente = quickSale.clienteId
      ? clientes.find(c => c.id === Number(quickSale.clienteId))
      : {
        id: 0,
        nombre: quickSale.clienteNombre.trim() || 'Cliente Genérico',
        dni: '',
        direccion: '',
      };

    const nuevaVenta = {
      id: `NV-${String(ventas.length + 1).padStart(4, '0')}`,
      fecha: quickSale.fecha,
      cliente,
      producto: {
        id: `custom-${Date.now()}`,
        nombre: quickSale.descripcion,
        unidad: quickSale.tipo,
      },
      tipo: quickSale.tipo,
      cantidad: parseFloat(quickSale.cantidad),
      precioUnit: parseFloat(quickSale.precioUnit),
      total: parseFloat(quickSale.precioUnit) * parseFloat(quickSale.cantidad),
    };

    agregarVenta(nuevaVenta);
    setNotaVisible(nuevaVenta);
    setQuickSale(f => ({ ...f, descripcion: '', cantidad: '', precioUnit: '', clienteId: '', clienteNombre: '' }));
  };

  return (
    <div className="inv-page">
      <div className="inv-header">
        <h2 className="inv-title">Inventario de Productos</h2>
        <button className="inv-btn-add" onClick={() => setMostrarForm(v => !v)}>
          {mostrarForm ? '✕ Cancelar' : '+ Agregar Producto'}
        </button>
      </div>

      <div className="inv-card inv-quick-card">
        <div className="inv-card-title">📝 Venta rápida / comprobante inmediato</div>
        <div className="inv-form-row">
          <div className="inv-group inv-full">
            <label>Descripción rápida</label>
            <textarea
              rows="2"
              placeholder="Escribe lo que vendes..."
              value={quickSale.descripcion}
              onChange={e => setQuickSale(f => ({ ...f, descripcion: e.target.value }))}
            />
          </div>
        </div>
        <div className="inv-form-row">
          <div className="inv-group inv-group-sm">
            <label>Fecha</label>
            <input
              type="date"
              value={quickSale.fecha}
              onChange={e => setQuickSale(f => ({ ...f, fecha: e.target.value }))}
            />
          </div>
          <div className="inv-group inv-group-sm">
            <label>Tipo</label>
            <select
              value={quickSale.tipo}
              onChange={e => setQuickSale(f => ({ ...f, tipo: e.target.value }))}
            >
              <option value="kg">Kg</option>
              <option value="unid">Unid</option>
              <option value="doc">Doc</option>
            </select>
          </div>
          <div className="inv-group inv-group-sm">
            <label>Precio unitario</label>
            <input
              type="number"
              step="0.50"
              min="0"
              placeholder="0.00"
              value={quickSale.precioUnit}
              onChange={e => setQuickSale(f => ({ ...f, precioUnit: e.target.value }))}
            />
          </div>
          <div className="inv-group inv-group-sm">
            <label>Cantidad</label>
            <input
              type="number"
              step="0.5"
              min="0"
              placeholder="0"
              value={quickSale.cantidad}
              onChange={e => setQuickSale(f => ({ ...f, cantidad: e.target.value }))}
            />
          </div>
        </div>
        <div className="inv-form-row">
          <div className="inv-group inv-grow">
            <label>Cliente</label>
            <select
              value={quickSale.clienteId}
              onChange={e => handleClienteChangeQuick(e.target.value)}
            >
              <option value="">— Seleccionar cliente —</option>
              {clientes.map(c => (
                <option key={c.id} value={c.id}>{c.nombre}</option>
              ))}
            </select>
          </div>
          <div className="inv-group inv-grow">
            <label>O nombre rápido</label>
            <input
              value={quickSale.clienteNombre}
              placeholder="Nombre del cliente..."
              onChange={e => setQuickSale(f => ({ ...f, clienteNombre: e.target.value, clienteId: '' }))}
            />
          </div>
        </div>
        <div className="inv-actions-row">
          <button className="inv-btn-save" onClick={handleRegistrarVentaRapida}>Registrar venta rápida</button>
          <button className="inv-btn-cancel" onClick={() => setQuickSale(f => ({ ...f, descripcion: '', cantidad: '', precioUnit: '', clienteId: '', clienteNombre: '' }))}>Limpiar</button>
        </div>
      </div>

      {mostrarForm && (
        <div className="inv-card inv-form-card">
          <div className="inv-card-title">Nuevo Producto</div>
          <div className="inv-form-row">
            <div className="inv-group">
              <label>Nombre</label>
              <input placeholder="Ej: Pollo Beneficiado"
                value={formNew.nombre}
                onChange={e => setFormNew(f => ({ ...f, nombre: e.target.value }))} />
            </div>
            <div className="inv-group inv-group-sm">
              <label>Unidad</label>
              <select value={formNew.unidad}
                onChange={e => setFormNew(f => ({ ...f, unidad: e.target.value }))}>
                <option value="kg">kg</option>
                <option value="unid">unid</option>
                <option value="doc">doc</option>
              </select>
            </div>
            <div className="inv-group inv-group-sm">
              <label>Precio (S/.)</label>
              <input type="number" step="0.5" min="0" placeholder="0.00"
                value={formNew.precio}
                onChange={e => setFormNew(f => ({ ...f, precio: e.target.value }))} />
            </div>
            <div className="inv-group inv-group-sm">
              <label>Stock inicial</label>
              <input type="number" min="0" placeholder="0"
                value={formNew.stock}
                onChange={e => setFormNew(f => ({ ...f, stock: e.target.value }))} />
            </div>
          </div>
          <button className="inv-btn-save" onClick={handleAgregar}>Guardar Producto</button>
        </div>
      )}

      <div className="inv-list">
        {productos.map(prod => (
          <div key={prod.id} className="inv-card">
            {editando?.id === prod.id ? (
              <EditProd prod={editando} onChange={setEditando} onSave={handleSaveEdit} onCancel={() => setEditando(null)} />
            ) : (
              <div className="inv-prod-row">
                <div className="inv-prod-info">
                  <span className="inv-prod-name">{prod.nombre}</span>
                  <span className="inv-prod-meta">{prod.unidad} · S/. {prod.precio.toFixed(2)}</span>
                </div>
                <div className="inv-prod-stock">
                  <span className={`inv-stock-badge ${prod.stock < 10 ? 'low' : 'ok'}`}>
                    Stock: {prod.stock} {prod.unidad}
                  </span>
                </div>
                <button className="inv-btn-edit" onClick={() => setEditando({ ...prod })}>✏️ Editar</button>
              </div>
            )}
          </div>
        ))}
      </div>
      {notaVisible && <NotaVenta venta={notaVisible} onClose={() => setNotaVisible(null)} />}
    </div>
  );
}

function EditProd({ prod, onChange, onSave, onCancel }) {
  return (
    <div className="inv-edit-form">
      <div className="inv-form-row">
        <div className="inv-group">
          <label>Nombre</label>
          <input value={prod.nombre}
            onChange={e => onChange(p => ({ ...p, nombre: e.target.value }))} />
        </div>
        <div className="inv-group inv-group-sm">
          <label>Precio (S/.)</label>
          <input type="number" step="0.5" value={prod.precio}
            onChange={e => onChange(p => ({ ...p, precio: parseFloat(e.target.value) || 0 }))} />
        </div>
        <div className="inv-group inv-group-sm">
          <label>Stock</label>
          <input type="number" value={prod.stock}
            onChange={e => onChange(p => ({ ...p, stock: parseFloat(e.target.value) || 0 }))} />
        </div>
      </div>
      <div className="inv-edit-actions">
        <button className="inv-btn-save" onClick={() => onSave(prod)}>Guardar</button>
        <button className="inv-btn-cancel" onClick={onCancel}>Cancelar</button>
      </div>
    </div>
  );
}
